  1→use std::collections::VecDeque;
  2→
  3→use cor24_emulator::{Assembler, EmulatorCore, StopReason};
  4→use gloo::timers::callback::Timeout;
  5→use web_sys::{HtmlInputElement, HtmlTextAreaElement, KeyboardEvent};
  6→use yew::prelude::*;
  7→
  8→use crate::config::{PreludeTier, StackSize};
  9→use crate::demos::DEMOS;
 10→
 11→/// Batch size per animation frame tick
 12→const BATCH_SIZE: u64 = 50_000;
 13→
 14→#[derive(Clone, Copy, PartialEq, Eq)]
 15→pub enum ViewMode {
 16→    Cli,
 17→    Split,
 18→}
 19→
 20→pub enum Msg {
 21→    Init,
 22→    Tick,
 23→    InputChanged(String),
 24→    Eval,
 25→    SetPrelude(PreludeTier),
 26→    SetStack(StackSize),
 27→    Reset,
 28→    LoadDemo(usize),
 29→    ToggleView,
 30→    ToggleSwitch,
 31→    ClearAll,
 32→    PauseResume,
 33→    /// Keydown in CLI input (Enter to eval)
 34→    CliKeyDown(KeyboardEvent),
 35→}
 36→
 37→pub struct Repl {
 38→    emulator: EmulatorCore,
 39→    /// Raw UART TX output from emulator (used by Split view)
 40→    output: String,
 41→    /// Interleaved transcript: UART output + echoed user input (used by CLI view)
 42→    transcript: String,
 43→    /// How many bytes of UART output we've already copied to transcript
 44→    uart_seen: usize,
 45→    input: String,
 46→    status: String,
 47→    running: bool,
 48→    loaded: bool,
 49→    waiting_for_input: bool,
 50→    uart_tx_queue: VecDeque<u8>,
 51→    prelude: PreludeTier,
 52→    stack_size: StackSize,
 53→    led_on: bool,
 54→    switch_pressed: bool,
 55→    view_mode: ViewMode,
 56→    selected_demo: Option<usize>,
 57→    /// Symbol addresses from assembly labels
 58→    addr_heap_next: Option<u32>,
 59→    addr_sym_count: Option<u32>,
 60→    addr_str_pool_next: Option<u32>,
 61→    /// Live memory readings
 62→    heap_used: u32,
 63→    sym_used: u32,
 64→    str_pool_used: u32,
 65→    stack_depth: u32,
 66→    input_ref: NodeRef,
 67→    cli_input_ref: NodeRef,
 68→}
 69→
 70→const HEAP_SIZE: u32 = 32768;
 71→const MAX_SYMBOLS: u32 = 512;
 72→const STR_POOL_SIZE: u32 = 8192;
 73→
 74→impl Repl {
 75→    fn load_binary(&mut self) {
 76→        let asm_source = self.prelude.assembly();
 77→        let mut asm = Assembler::new();
 78→        let result = asm.assemble(asm_source);
 79→
 80→        if !result.errors.is_empty() {
 81→            self.status = format!("Assembly failed: {}", result.errors[0]);
 82→            self.loaded = false;
 83→            return;
 84→        }
 85→
 86→        self.emulator.hard_reset();
 87→        self.emulator.set_uart_tx_busy_cycles(0); // instant TX in browser
 88→        for (addr, &byte) in result.bytes.iter().enumerate() {
 89→            self.emulator.write_byte(addr as u32, byte);
 90→        }
 91→        self.emulator.set_pc(0);
 92→        self.emulator.set_reg(4, self.stack_size.initial_sp());
 93→
 94→        // Capture memory pool addresses from symbol table
 95→        self.addr_heap_next = result.labels.get("_heap_next").copied();
 96→        self.addr_sym_count = result.labels.get("_sym_count").copied();
 97→        self.addr_str_pool_next = result.labels.get("_str_pool_next").copied();
 98→
 99→        self.output.clear();
100→        self.transcript.clear();
101→        self.uart_seen = 0;
102→        self.uart_tx_queue.clear();
103→        self.loaded = true;
104→        self.waiting_for_input = false;
105→        self.led_on = false;
106→        self.switch_pressed = false;
107→        self.heap_used = 0;
108→        self.sym_used = 0;
109→        self.str_pool_used = 0;
110→        self.stack_depth = 0;
111→        self.status = format!(
112→            "Loaded {} bytes ({}, {} stack).",
113→            result.bytes.len(),
114→            self.prelude.label(),
115→            self.stack_size.label(),
116→        );
117→
118→        self.emulator.resume();
119→        self.running = true;
120→    }
121→
122→    fn view_gauge(&self, label: &str, used: u32, total: u32) -> Html {
123→        let pct = if total > 0 { (used as f64 / total as f64 * 100.0).min(100.0) } else { 0.0 };
124→        let color_class = if pct < 60.0 { "gauge-green" }
125→            else if pct < 85.0 { "gauge-yellow" }
126→            else { "gauge-red" };
127→        html! {
128→            <div class="gauge-row">
129→                <span class="gauge-label">{ label }</span>
130→                <div class="gauge-track">
131→                    <div class={classes!("gauge-fill", color_class)}
132→                         style={format!("width:{}%", pct)} />
133→                </div>
134→                <span class="gauge-text">{ format!("{}/{}", used, total) }</span>
135→            </div>
136→        }
137→    }
138→
139→    fn send_input(&mut self) {
140→        for line in self.input.lines() {
141→            if line.trim().is_empty() {
142→                continue;
143→            }
144→            for byte in line.bytes() {
145→                self.uart_tx_queue.push_back(byte);
146→            }
147→            self.uart_tx_queue.push_back(b'\n');
148→        }
149→    }
150→}
151→
152→impl Component for Repl {
153→    type Message = Msg;
154→    type Properties = ();
155→
156→    fn create(ctx: &Context<Self>) -> Self {
157→        ctx.link().send_message(Msg::Init);
158→
159→        Self {
160→            emulator: {
161→                let mut emu = EmulatorCore::new();
162→                emu.set_uart_tx_busy_cycles(0); // instant TX in browser
163→                emu
164→            },
165→            output: String::new(),
166→            transcript: String::new(),
167→            uart_seen: 0,
168→            input: String::from("(+ 1 2)"),
169→            status: "Assembling interpreter...".into(),
170→            running: false,
171→            loaded: false,
172→            waiting_for_input: false,
173→            uart_tx_queue: VecDeque::new(),
174→            prelude: PreludeTier::Standard,
175→            stack_size: StackSize::ThreeKb,
176→            led_on: false,
177→            switch_pressed: false,
178→            view_mode: ViewMode::Cli,
179→            selected_demo: None,
180→            addr_heap_next: None,
181→            addr_sym_count: None,
182→            addr_str_pool_next: None,
183→            heap_used: 0,
184→            sym_used: 0,
185→            str_pool_used: 0,
186→            stack_depth: 0,
187→            input_ref: NodeRef::default(),
188→            cli_input_ref: NodeRef::default(),
189→        }
190→    }
191→
192→    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
193→        match msg {
194→            Msg::Init => {
195→                self.load_binary();
196→                if self.loaded {
197→                    ctx.link().send_message(Msg::Tick);
198→                }
199→                true
200→            }
201→
202→            Msg::Tick => {
203→                if !self.running {
204→                    return false;
205→                }
206→
207→                // Feed queued bytes: poll-before-feed (match cor24-run).
208→                // Budget limits total instructions to avoid blocking the
209→                // browser when the interpreter is busy evaluating.
210→                let mut feed_budget: u32 = 10_000;
211→                while !self.uart_tx_queue.is_empty() && feed_budget > 0 {
212→                    let status = self.emulator.read_byte(0xFF0101);
213→                    if status & 0x01 != 0 {
214→                        // CPU hasn't consumed previous byte — run a bit more
215→                        self.emulator.run_batch(50);
216→                        feed_budget = feed_budget.saturating_sub(50);
217→                        continue;
218→                    }
219→                    let byte = self.uart_tx_queue.pop_front().unwrap();
220→                    self.emulator.send_uart_byte(byte);
221→                    self.emulator.run_batch(50);
222→                    feed_budget = feed_budget.saturating_sub(50);
223→                    if byte == b'\n' {
224→                        break;
225→                    }
226→                }
227→
228→                let result = self.emulator.run_batch(BATCH_SIZE);
229→
230→                if result.led_changed {
231→                    self.led_on = self.emulator.get_led() & 1 != 0;
232→                }
233→
234→                // Sample memory usage from runtime globals
235→                if let Some(addr) = self.addr_heap_next {
236→                    self.heap_used = self.emulator.read_word(addr);
237→                }
238→                if let Some(addr) = self.addr_sym_count {
239→                    self.sym_used = self.emulator.read_word(addr);
240→                }
241→                if let Some(addr) = self.addr_str_pool_next {
242→                    self.str_pool_used = self.emulator.read_word(addr);
243→                }
244→                let sp = self.emulator.get_reg(4);
245→                self.stack_depth = self.stack_size.initial_sp().saturating_sub(sp);
246→
247→                let uart = self.emulator.get_uart_output();
248→                // Append new UART bytes to transcript (CLI view)
249→                if uart.len() > self.uart_seen {
250→                    self.transcript.push_str(&uart[self.uart_seen..]);
251→                    self.uart_seen = uart.len();
252→                }
253→                // Update raw output (Split view)
254→                let uart_owned = uart.to_string();
255→                if uart_owned != self.output {
256→                    self.output = uart_owned;
257→                }
258→
259→                match result.reason {
260→                    StopReason::CycleLimit => {
261→                        let at_prompt = self.uart_tx_queue.is_empty()
262→                            && self.output.ends_with("> ");
263→
264→                        if at_prompt {
265→                            self.running = false;
266→                            self.waiting_for_input = true;
267→                            self.status = "Ready.".into();
268→                        } else {
269→                            let link = ctx.link().clone();
270→                            Timeout::new(25, move || link.send_message(Msg::Tick)).forget();
271→                        }
272→                    }
273→                    StopReason::Halted => {
274→                        self.running = false;
275→                        self.waiting_for_input = false;
276→                        self.status = "Program finished.".into();
277→                    }
278→                    StopReason::InvalidInstruction(byte) => {
279→                        self.running = false;
280→                        self.status = format!(
281→                            "Invalid instruction 0x{:02X} at PC=0x{:06X}",
282→                            byte,
283→                            self.emulator.pc()
284→                        );
285→                    }
286→                    StopReason::Breakpoint(addr) => {
287→                        self.running = false;
288→                        self.status = format!("Breakpoint at 0x{:06X}", addr);
289→                    }
290→                    StopReason::Paused => {
291→                        self.running = false;
292→                        self.status = "Paused.".into();
293→                    }
294→                }
295→                true
296→            }
297→
298→            Msg::InputChanged(value) => {
299→                self.input = value;
300→                false
301→            }
302→
303→            Msg::Eval => {
304→                if !self.loaded {
305→                    return true;
306→                }
307→                // Echo input to transcript (CLI view shows interleaved I/O)
308→                for line in self.input.lines() {
309→                    if !line.trim().is_empty() {
310→                        self.transcript.push_str(line);
311→                        self.transcript.push('\n');
312→                    }
313→                }
314→                self.send_input();
315→                self.status = "Evaluating...".into();
316→                self.waiting_for_input = false;
317→                if !self.running {
318→                    self.emulator.resume();
319→                    self.running = true;
320→                    ctx.link().send_message(Msg::Tick);
321→                }
322→                // In CLI mode, clear the input after sending
323→                if self.view_mode == ViewMode::Cli {
324→                    self.input.clear();
325→                }
326→                true
327→            }
328→
329→            Msg::CliKeyDown(e) => {
330→                if e.key() == "Enter" && !e.shift_key() {
331→                    e.prevent_default();
332→                    ctx.link().send_message(Msg::Eval);
333→                }
334→                false
335→            }
336→
337→            Msg::SetPrelude(tier) => {
338→                if tier != self.prelude {
339→                    self.prelude = tier;
340→                    self.running = false;
341→                    self.load_binary();
342→                    if self.loaded {
343→                        ctx.link().send_message(Msg::Tick);
344→                    }
345→                }
346→                true
347→            }
348→
349→            Msg::SetStack(size) => {
350→                if size != self.stack_size {
351→                    self.stack_size = size;
352→                    self.running = false;
353→                    self.load_binary();
354→                    if self.loaded {
355→                        ctx.link().send_message(Msg::Tick);
356→                    }
357→                }
358→                true
359→            }
360→
361→            Msg::Reset => {
362→                self.running = false;
363→                self.load_binary();
364→                if self.loaded {
365→                    ctx.link().send_message(Msg::Tick);
366→                }
367→                true
368→            }
369→
370→            Msg::LoadDemo(index) => {
371→                if let Some(demo) = DEMOS.get(index) {
372→                    self.selected_demo = Some(index);
373→                    self.input = demo.source.trim().to_string();
374→                    self.prelude = demo.prelude;
375→                    self.stack_size = demo.stack;
376→                    // Always reset emulator for a clean demo run
377→                    self.running = false;
378→                    self.load_binary();
379→                    if self.loaded {
380→                        ctx.link().send_message(Msg::Tick);
381→                    }
382→                    // Switch to Split view for demos (multi-line code)
383→                    self.view_mode = ViewMode::Split;
384→                }
385→                true
386→            }
387→
388→            Msg::ToggleView => {
389→                self.view_mode = match self.view_mode {
390→                    ViewMode::Cli => ViewMode::Split,
391→                    ViewMode::Split => ViewMode::Cli,
392→                };
393→                true
394→            }
395→
396→            Msg::ToggleSwitch => {
397→                self.switch_pressed = !self.switch_pressed;
398→                self.emulator.set_button_pressed(self.switch_pressed);
399→                true
400→            }
401→
402→            Msg::ClearAll => {
403→                self.emulator.clear_uart_output();
404→                self.output.clear();
405→                self.transcript.clear();
406→                self.uart_seen = 0;
407→                self.input.clear();
408→                self.selected_demo = None;
409→                true
410→            }
411→
412→            Msg::PauseResume => {
413→                if self.running {
414→                    // Pause
415→                    self.running = false;
416→                    self.status = "Paused.".into();
417→                } else if self.loaded {
418→                    // Resume
419→                    self.emulator.resume();
420→                    self.running = true;
421→                    self.waiting_for_input = false;
422→                    self.status = "Running...".into();
423→                    ctx.link().send_message(Msg::Tick);
424→                }
425→                true
426→            }
427→        }
428→    }
429→
430→    fn view(&self, ctx: &Context<Self>) -> Html {
431→        let on_eval = ctx.link().callback(|_| Msg::Eval);
432→        let on_reset = ctx.link().callback(|_| Msg::Reset);
433→        let on_toggle_view = ctx.link().callback(|_| Msg::ToggleView);
434→        let on_toggle_switch = ctx.link().callback(|_| Msg::ToggleSwitch);
435→        let on_clear = ctx.link().callback(|_| Msg::ClearAll);
436→        let on_pause = ctx.link().callback(|_| Msg::PauseResume);
437→
438→        let on_prelude = ctx.link().callback(|e: Event| {
439→            let target: web_sys::HtmlSelectElement = e.target_unchecked_into();
440→            let tier = match target.value().as_str() {
441→                "bare" => PreludeTier::Bare,
442→                "minimal" => PreludeTier::Minimal,
443→                "full" => PreludeTier::Full,
444→                "scheme" => PreludeTier::Scheme,
445→                _ => PreludeTier::Standard,
446→            };
447→            Msg::SetPrelude(tier)
448→        });
449→
450→        let on_stack = ctx.link().callback(|e: Event| {
451→            let target: web_sys::HtmlSelectElement = e.target_unchecked_into();
452→            let size = match target.value().as_str() {
453→                "8" => StackSize::EightKb,
454→                _ => StackSize::ThreeKb,
455→            };
456→            Msg::SetStack(size)
457→        });
458→
459→        let on_demo = ctx.link().callback(|e: Event| {
460→            let target: web_sys::HtmlSelectElement = e.target_unchecked_into();
461→            let idx: usize = target.value().parse().unwrap_or(usize::MAX);
462→            Msg::LoadDemo(idx)
463→        });
464→
465→        let eval_disabled = (!self.waiting_for_input && self.running) || !self.loaded;
466→        let show_spinner = self.running && !self.waiting_for_input;
467→        let view_label = match self.view_mode {
468→            ViewMode::Cli => "Split",
469→            ViewMode::Split => "CLI",
470→        };
471→
472→        html! {
473→            <div class="repl-container">
474→                // Toolbar
475→                <div class="toolbar">
476→                    <label class="toolbar-item">
477→                        {"Prelude"}
478→                        <select onchange={on_prelude}>
479→                            { for PreludeTier::ALL.iter().map(|t| {
480→                                let val = match t {
481→                                    PreludeTier::Bare => "bare",
482→                                    PreludeTier::Minimal => "minimal",
483→                                    PreludeTier::Standard => "standard",
484→                                    PreludeTier::Full => "full",
485→                                    PreludeTier::Scheme => "scheme",
486→                                };
487→                                html! {
488→                                    <option value={val} selected={*t == self.prelude}>
489→                                        { t.label() }
490→                                    </option>
491→                                }
492→                            })}
493→                        </select>
494→                    </label>
495→                    <label class="toolbar-item">
496→                        {"Stack"}
497→                        <select onchange={on_stack}>
498→                            { for StackSize::ALL.iter().map(|s| {
499→                                let val = match s {
500→                                    StackSize::ThreeKb => "3",
501→                                    StackSize::EightKb => "8",
502→                                };
503→                                html! {
504→                                    <option value={val} selected={*s == self.stack_size}>
505→                                        { s.label() }
506→                                    </option>
507→                                }
508→                            })}
509→                        </select>
510→                    </label>
511→                    <label class="toolbar-item">
512→                        {"Demo"}
513→                        <select onchange={on_demo}>
514→                            <option value="" selected={self.selected_demo.is_none()}>{"— select —"}</option>
515→                            { for PreludeTier::ALL.iter().filter(|tier| {
516→                                DEMOS.iter().any(|d| d.prelude == **tier)
517→                            }).map(|tier| {
518→                                let label = format!("{} prelude", tier.label());
519→                                html! {
520→                                    <optgroup label={label}>
521→                                        { for DEMOS.iter().enumerate()
522→                                            .filter(move |(_, d)| d.prelude == *tier)
523→                                            .map(|(i, d)| {
524→                                                let stack_note = if d.stack == StackSize::EightKb {
525→                                                    " [8K]"
526→                                                } else {
527→                                                    ""
528→                                                };
529→                                                let sel = self.selected_demo == Some(i);
530→                                                html! {
531→                                                    <option value={i.to_string()} selected={sel}>
532→                                                        { format!("{}{}", d.title, stack_note) }
533→                                                    </option>
534→                                                }
535→                                            })
536→                                        }
537→                                    </optgroup>
538→                                }
539→                            })}
540→                        </select>
541→                    </label>
542→                    <button class="toolbar-btn" onclick={on_toggle_view}>{ view_label }</button>
543→                    <button class="toolbar-btn" onclick={on_pause}>
544→                        { if self.running { "Pause" } else { "Resume" } }
545→                    </button>
546→                    <button class="toolbar-btn" onclick={on_reset}>{"Reset"}</button>
547→                    <button class="toolbar-btn" onclick={on_clear}>{"Clear"}</button>
548→                    <span class="toolbar-desc">{ self.prelude.description() }</span>
549→                </div>
550→
551→                // Main area (output is always full-size)
552→                <div class="main-area">
553→                    // Output panel (full size)
554→                    // CLI view: interleaved transcript; Split view: raw UART output
555→                    <pre class="output">{ match self.view_mode {
556→                        ViewMode::Cli => &self.transcript,
557→                        ViewMode::Split => &self.output,
558→                    }}</pre>
559→
560→                    // Floating hardware + memory panel (top-right)
561→                    <div class="hw-float">
562→                        <div class="hw-row">
563→                            <span class="hw-label">{"D2"}</span>
564→                            <div class={if self.led_on { "led led-on" } else { "led led-off" }} />
565→                        </div>
566→                        <div class="hw-row">
567→                            <span class="hw-label">{"S2"}</span>
568→                            <div class={if self.switch_pressed { "switch switch-on" } else { "switch switch-off" }}
569→                                 onclick={on_toggle_switch} />
570→                        </div>
571→                        <div class="hw-sep" />
572→                        { self.view_gauge("Heap", self.heap_used, HEAP_SIZE) }
573→                        { self.view_gauge("Syms", self.sym_used, MAX_SYMBOLS) }
574→                        { self.view_gauge("Strs", self.str_pool_used, STR_POOL_SIZE) }
575→                        { self.view_gauge("Stack", self.stack_depth, self.stack_size.bytes()) }
576→                    </div>
577→
578→                    // Input area depends on view mode
579→                    { match self.view_mode {
580→                        ViewMode::Cli => {
581→                            let on_cli_input = ctx.link().callback(|e: InputEvent| {
582→                                let target: HtmlInputElement = e.target_unchecked_into();
583→                                Msg::InputChanged(target.value())
584→                            });
585→                            let on_keydown = ctx.link().callback(Msg::CliKeyDown);
586→                            html! {
587→                                <div class="cli-input-bar">
588→                                    <span class="cli-prompt">{"> "}</span>
589→                                    <input
590→                                        ref={self.cli_input_ref.clone()}
591→                                        type="text"
592→                                        class="cli-input"
593→                                        value={self.input.clone()}
594→                                        oninput={on_cli_input}
595→                                        onkeydown={on_keydown}
596→                                        placeholder="(+ 1 2)"
597→                                        spellcheck="false"
598→                                        disabled={eval_disabled}
599→                                    />
600→                                    { if show_spinner { html! { <span class="spinner" /> } } else { html! {} } }
601→                                    <span class="cli-status">{ &self.status }</span>
602→                                </div>
603→                            }
604→                        }
605→                        ViewMode::Split => {
606→                            let on_textarea = ctx.link().callback(|e: InputEvent| {
607→                                let target: HtmlTextAreaElement = e.target_unchecked_into();
608→                                Msg::InputChanged(target.value())
609→                            });
610→                            html! {
611→                                <div class="split-input-overlay">
612→                                    <textarea
613→                                        ref={self.input_ref.clone()}
614→                                        class="split-textarea"
615→                                        value={self.input.clone()}
616→                                        oninput={on_textarea}
617→                                        placeholder="(+ 1 2)"
618→                                        spellcheck="false"
619→                                    />
620→                                    <div class="split-controls">
621→                                        <button class="eval-btn" onclick={on_eval} disabled={eval_disabled}>
622→                                            {"Eval"}
623→                                        </button>
624→                                        { if show_spinner { html! { <span class="spinner" /> } } else { html! {} } }
625→                                        <span class="status">{ &self.status }</span>
626→                                    </div>
627→                                </div>
628→                            }
629→                        }
630→                    }}
631→                </div>
632→
633→                <style>{include_str!("repl.css")}</style>
634→            </div>
